INSERT INTO hadiths (id, sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (1, 'Début de la révélation ', 'Al-Bukhari', NULL, 'Sahih', 'قَالَ الشَّيْخُ الْإِمَامُ الْحَافِظُ أَبُو عَبْدِ اللَّهِ مُحَمَّدُ بْنُ إِسْمَاعِيلَ بْنِ إِبْرَاهِيمَ بْنِ الْمُغِيرَةِ الْبُخَارِيُّ رَحِمَهُ اللَّهُ تَعَالَى آمِينَ:
INSERT INTO hadiths (id, sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (2, 'Début de la révélation ', 'Al-Bukhari', '`Aichah', 'Sahih', 'قَالَ: حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ، قَالَ: أَخْبَرَنَا مَالِكٌ، عَنْ هِشَامِ بْنِ عُرْوَةَ، عَنْ أَبِيهِ، عَنْ عَائِشَةَ أُمِّ المُؤْمِنِينَ رَضِيَ اللَّهُ عَنْهَا، أَنَّ الحَارِثَ بْنَ هِشَامٍ رَضِيَ اللَّهُ عَنْهُ سَأَلَ رَسُولَ اللَّهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ ¬¬¬فَقَالَ: يَا رَسُولَ اللَّهِ، كَيْفَ يَأْتِيكَ الوَحْيُ؟ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ: "أَحْيَانًا يَأْتِينِي مِثْلَ صَلْصَلَةِ الجَرَسِ، وَهُوَ أَشَدُّهُ عَلَيَّ، فَيُفْصَمُ عَنِّي وَقَدْ وَعَيْتُ عَنْهُ مَا قَالَ، وَأَحْيَانًا يَتَمَثَّلُ لِيَ المَلَكُ رَجُلًا فَيُكَلِّمُنِي فَأَعِي مَا يَقُولُ" قَالَتْ عَائِشَةُ رَضِيَ اللَّهُ عَنْهَا: وَلَقَدْ رَأَيْتُهُ يَنْزِلُ عَلَيْهِ الوَحْيُ فِي اليَوْمِ الشَّدِيدِ البَرْدِ، فَيَفْصِمُ عَنْهُ وَإِنَّ جَبِينَهُ لَيَتَفَصَّدُ عَرَقًا.
INSERT INTO hadiths (id, sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (3, 'Début de la révélation', 'Al-Bukhari', 'Omar Ibnou Al-Khattab', 'Sahih', ' قَالَ: حَدَّثَنَا الحُمَيْدِيُّ عَبْدُ اللَّهِ بْنُ الزُّبَيْرِ، قَالَ: حَدَّثَنَا سُفْيَانُ، قَالَ: حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ الأَنْصَارِيُّ، قَالَ: أَخْبَرَنِي مُحَمَّدُ بْنُ إِبْرَاهِيمَ التَّيْمِيُّ، أَنَّهُ سَمِعَ عَلْقَمَةَ بْنَ وَقَّاصٍ اللَّيْثِيَّ، يَقُولُ: سَمِعْتُ عُمَرَ بْنَ الخَطَّابِ رَضِيَ اللَّهُ عَنْهُ عَلَى المِنْبَرِ قَالَ: سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ يَقُولُ: "إِنَّمَا الأَعْمَالُ بِالنِّيَّاتِ، وَإِنَّمَا لِكُلِّ امْرِئٍ مَا نَوَى، فَمَنْ كَانَتْ هِجْرَتُهُ إِلَى دُنْيَا يُصِيبُهَا، أَوْ إِلَى امْرَأَةٍ يَنْكِحُهَا، فَهِجْرَتُهُ إِلَى مَا هَاجَرَ إِلَيْهِ".', NULL, NULL, NULL, 'intention, actes');
INSERT INTO hadiths (id, sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (4, 'Début de la révélation', 'Al-Bukhari', '`Aichah', 'Sahih', ' قَالَ: حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ، قَالَ: حَدَّثَنَا اللَّيْثُ، عَنْ عُقَيْلٍ، عَنِ ابْنِ شِهَابٍ، عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ، عَنْ عَائِشَةَ أُمِّ المُؤْمِنِينَ أَنَّهُا قَالَتْ: أَوَّلُ مَا بُدِئَ بِهِ رَسُولُ اللَّهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ مِنَ الوَحْيِ الرُّؤْيَا الصَّالِحَةُ فِي النَّوْمِ، فَكَانَ لاَ يَرَى رُؤْيَا إِلَّا جَاءَتْ مِثْلَ فَلَقِ الصُّبْحِ، ثُمَّ حُبِّبَ إِلَيْهِ الخَلاَءُ، وَكَانَ يَخْلُو بِغَارِ حِرَاءٍ فَيَتَحَنَّثُ فِيهِ - وَهُوَ التَّعَبُّدُ - اللَّيَالِيَ ذَوَاتِ العَدَدِ قَبْلَ أَنْ يَنْزِعَ إِلَى أَهْلِهِ، وَيَتَزَوَّدُ لِذَلِكَ، ثُمَّ يَرْجِعُ إِلَى خَدِيجَةَ فَيَتَزَوَّدُ لِمِثْلِهَا، حَتَّى جَاءَهُ الحَقُّ وَهُوَ فِي غَارِ حِرَاءٍ، فَجَاءَهُ المَلَكُ فَقَالَ: اقْرَأْ، قَالَ: "مَا أَنَا بِقَارِئٍ"، قَالَ: "فَأَخَذَنِي فَغَطَّنِي حَتَّى بَلَغَ مِنِّي الجَهْدَ ثُمَّ أَرْسَلَنِي، فَقَالَ: اقْرَأْ، قُلْتُ: مَا أَنَا بِقَارِئٍ، فَأَخَذَنِي فَغَطَّنِي الثَّانِيَةَ حَتَّى بَلَغَ مِنِّي الجَهْدَ ثُمَّ أَرْسَلَنِي، فَقَالَ: اقْرَأْ، فَقُلْتُ: مَا أَنَا بِقَارِئٍ، فَأَخَذَنِي فَغَطَّنِي الثَّالِثَةَ ثُمَّ أَرْسَلَنِي، فَقَالَ: ﴿اقْرَأْ بِاسْمِ رَبِّكَ الَّذِي خَلَقَ. خَلَقَ الإِنْسَانَ مِنْ عَلَقٍ. اقْرَأْ وَرَبُّكَ الأَكْرَمُ﴾ [العلق: 2] " فَرَجَعَ بِهَا رَسُولُ اللَّهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ يَرْجُفُ فُؤَادُهُ، فَدَخَلَ عَلَى خَدِيجَةَ بِنْتِ خُوَيْلِدٍ رَضِيَ اللَّهُ عَنْهَا، فَقَالَ: "زَمِّلُونِي زَمِّلُونِي" فَزَمَّلُوهُ حَتَّى ذَهَبَ عَنْهُ الرَّوْعُ، فَقَالَ لِخَدِيجَةَ وَأَخْبَرَهَا الخَبَرَ: "لَقَدْ خَشِيتُ عَلَى نَفْسِ" فَقَالَتْ خَدِيجَةُ: "كَلَّا وَاللَّهِ مَا يُخْزِيكَ اللَّهُ أَبَدًا، إِنَّكَ لَتَصِلُ الرَّحِمَ، وَتَحْمِلُ الكَلَّ، وَتَكْسِبُ المَعْدُومَ، وَتَقْرِي الضَّيْفَ، وَتُعِينُ عَلَى نَوَائِبِ الحَقِّ"، فَانْطَلَقَتْ بِهِ خَدِيجَةُ حَتَّى أَتَتْ بِهِ وَرَقَةَ بْنَ نَوْفَلِ بْنِ أَسَدِ بْنِ عَبْدِ العُزَّى ابْنَ عَمِّ خَدِيجَةَ وَكَانَ امْرَأً تَنَصَّرَ فِي الجَاهِلِيَّةِ، وَكَانَ يَكْتُبُ الكِتَابَ العِبْرَانِيَّ، فَيَكْتُبُ مِنَ الإِنْجِيلِ بِالعِبْرَانِيَّةِ مَا شَاءَ اللَّهُ أَنْ يَكْتُبَ، وَكَانَ شَيْخًا كَبِيرًا قَدْ عَمِيَ، فَقَالَتْ لَهُ خَدِيجَةُ: "يَا ابْنَ عَمِّ، اسْمَعْ مِنَ ابْنِ أَخِيكَ"، فَقَالَ لَهُ وَرَقَةُ: "يَا ابْنَ أَخِي مَاذَا تَرَى؟" فَأَخْبَرَهُ رَسُولُ اللَّهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ خَبَرَ مَا رَأَى، فَقَالَ لَهُ وَرَقَةُ: "هَذَا النَّامُوسُ الَّذِي نَزَّلَ اللَّهُ عَلَى مُوسَى، يَا لَيْتَنِي فِيهَا جَذَعًا، لَيْتَنِي أَكُونُ حَيًّا إِذْ يُخْرِجُكَ قَوْمُكَ"، فَقَالَ رَسُولُ اللَّهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ: "أَوَ مُخْرِجِيَّ هُمْ"، قَالَ: نَعَمْ، لَمْ يَأْتِ رَجُلٌ قَطُّ بِمِثْلِ مَا جِئْتَ بِهِ إِلَّا عُودِيَ، وَإِنْ يُدْرِكْنِي يَوْمُكَ أَنْصُرْكَ نَصْرًا مُؤَزَّرًا. ثُمَّ لَمْ يَنْشَبْ وَرَقَةُ أَنْ تُوُفِّيَ، وَفَتَرَ الوَحْيُ.', NULL, NULL, NULL, 'Révélation, croyance');
INSERT INTO hadiths (id, sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (5, 'Début de la révélation', 'Al-Bukhari', NULL, 'Sahih', 'قَالَ ابْنُ شِهَابٍ: وَأَخْبَرَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ، أَنَّ جَابِرَ بْنَ عَبْدِ اللَّهِ الأَنْصَارِيَّ، قَالَ: وَهُوَ يُحَدِّثُ عَنْ فَتْرَةِ الوَحْيِ فَقَالَ فِي حَدِيثِهِ: "بَيْنَا أَنَا أَمْشِي إِذْ سَمِعْتُ صَوْتًا مِنَ السَّمَاءِ، فَرَفَعْتُ بَصَرِي، فَإِذَا المَلَكُ الَّذِي جَاءَنِي بِحِرَاءٍ جَالِسٌ عَلَى كُرْسِيٍّ بَيْنَ السَّمَاءِ وَالأَرْضِ، فَرُعِبْتُ مِنْهُ، فَرَجَعْتُ فَقُلْتُ: زَمِّلُونِي زَمِّلُونِي" فَأَنْزَلَ اللَّهُ تَعَالَى: ﴿يَا أَيُّهَا المُدَّثِّرُ. قُمْ فَأَنْذِرْ﴾ [المدثر: 2] إِلَى قَوْلِهِ ﴿وَالرِّجْزَ فَاهْجُرْ﴾ [المدثر: 5]. فَحَمِيَ الوَحْيُ وَتَتَابَعَ تَابَعَهُ عَبْدُ اللَّهِ بْنُ يُوسُفَ، وَأَبُو صَالِحٍ، وَتَابَعَهُ هِلاَلُ بْنُ رَدَّادٍ، عَنِ الزُّهْرِيِّ، وَقَالَ يُونُسُ، وَمَعْمَرٌ بَوَادِرُهُ.', NULL, NULL, NULL, 'Révélation, croyance');
INSERT INTO hadiths (id, sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (6, 'Début de la révélation', 'Al-Bukhari', 'Ibnou l-`abbās', 'Sahih', 'قَالَ: حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ، قَالَ: حَدَّثَنَا أَبُو عَوَانَةَ، قَالَ: حَدَّثَنَا مُوسَى بْنُ أَبِي عَائِشَةَ، قَالَ: حَدَّثَنَا سَعِيدُ بْنُ جُبَيْرٍ، عَنِ ابْنِ عَبَّاسٍ فِي قَوْلِهِ تَعَالَى: ﴿لاَ تُحَرِّكْ بِهِ لِسَانَكَ لِتَعْجَلَ بِهِ﴾ [القيامة: 16] قَالَ: كَانَ رَسُولُ اللَّهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ يُعَالِجُ مِنَ التَّنْزِيلِ شِدَّةً، وَكَانَ مِمَّا يُحَرِّكُ شَفَتَيْهِ - فَقَالَ ابْنُ عَبَّاسٍ: فَأَنَا أُحَرِّكُهُمَا لَكُمْ كَمَا كَانَ رَسُولُ اللَّهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ يُحَرِّكُهُمَا، وَقَالَ سَعِيدٌ: أَنَا أُحَرِّكُهُمَا كَمَا رَأَيْتُ ابْنَ عَبَّاسٍ يُحَرِّكُهُمَا، فَحَرَّكَ شَفَتَيْهِ - فَأَنْزَلَ اللَّهُ تَعَالَى: ﴿لاَ تُحَرِّكْ بِهِ لِسَانَكَ لِتَعْجَلَ بِهِ إِنَّ عَلَيْنَا جَمْعَهُ وَقُرْآنَهُ﴾ [القيامة: 17] قَالَ: جَمْعُهُ لهُ فِي صَدْرِكَ وَتَقْرَأَهُ: ﴿فَإِذَا قَرَأْنَاهُ فَاتَّبِعْ قُرْآنَهُ﴾ [القيامة: 18] قَالَ: فَاسْتَمِعْ لَهُ وَأَنْصِتْ: ﴿ثُمَّ إِنَّ عَلَيْنَا بَيَانَهُ﴾ [القيامة: 19] ثُمَّ إِنَّ عَلَيْنَا أَنْ تَقْرَأَهُ، فَكَانَ رَسُولُ اللَّهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ بَعْدَ ذَلِكَ إِذَا أَتَاهُ جِبْرِيلُ اسْتَمَعَ فَإِذَا انْطَلَقَ جِبْرِيلُ قَرَأَهُ النَّبِيُّ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ كَمَا قَرَأَهُ.', NULL, NULL, NULL, 'Révélation, croyance');
INSERT INTO hadiths (id, sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (7, 'Début de la révélation', 'Al-Bukhari', 'Ibnou l-`abbās', 'Sahih', 'قَالَ: حَدَّثَنَا عَبْدَانُ، قَالَ: أَخْبَرَنَا عَبْدُ اللَّهِ قَالَ: أَخْبَرَنَا يُونُسُ، عَنِ الزُّهْرِيِّ، ح وحَدَّثَنَا بِشْرُ بْنُ مُحَمَّدٍ، قَالَ: أَخْبَرَنَا عَبْدُ اللَّهِ، قَالَ: أَخْبَرَنَا يُونُسُ، وَمَعْمَرٌ، عَنِ الزُّهْرِيِّ، نَحْوَهُ قَالَ: أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ، عَنِ ابْنِ عَبَّاسٍ،أَنَّهُ قَالَ: "كَانَ رَسُولُ اللَّهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ أَجْوَدَ النَّاسِ، وَكَانَ أَجْوَدُ مَا يَكُونُ فِي رَمَضَانَ حِينَ يَلْقَاهُ جِبْرِيلُ، وَكَانَ يَلْقَاهُ فِي كُلِّ لَيْلَةٍ مِنْ رَمَضَانَ فَيُدَارِسُهُ القُرْآنَ، فَلَرَسُولُ اللَّهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ أَجْوَدُ بِالخَيْرِ مِنَ الرِّيحِ المُرْسَلَةِ".', NULL, NULL, NULL, 'Révélation, croyance');
INSERT INTO hadiths (id, sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (8, 'Début de la révélation', 'Al-Bukhari', NULL, 'Sahih', 'قَالَ: حَدَّثَنَا أَبُو اليَمَانِ الحَكَمُ بْنُ نَافِعٍ قَالَ: أَخْبَرَنَا شُعَيْبٌ، عَنِ الزُّهْرِيِّ قَالَ: أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ عُتْبَةَ بْنِ مَسْعُودٍ، أَنَّ عَبْدَ اللَّهِ بْنَ عَبَّاسٍ، أَخْبَرَهُ أَنَّ أَبَا سُفْيَانَ بْنَ حَرْبٍ أَخْبَرَهُ: أَنَّ هِرَقْلَ أَرْسَلَ إِلَيْهِ فِي رَكْبٍ مِنْ قُرَيْشٍ، وَكَانُوا تُجَّارًا بِالشَّأْمِ فِي المُدَّةِ الَّتِي كَانَ رَسُولُ اللَّهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ مَادَّ فِيهَا أَبَا سُفْيَانَ وَكُفَّارَ قُرَيْشٍ، فَأَتَوْهُ وَهُمْ بِإِيلِيَاءَ، فَدَعَاهُمْ فِي مَجْلِسِهِ، وَحَوْلَهُ عُظَمَاءُ الرُّومِ، ثُمَّ دَعَاهُمْ وَدَعَا بِتَرْجُمَانِهِ، فَقَالَ: أَيُّكُمْ أَقْرَبُ نَسَبًا بِهَذَا الرَّجُلِ الَّذِي يَزْعُمُ أَنَّهُ نَبِيٌّ؟ فَقَالَ أَبُو سُفْيَانَ: فَقُلْتُ: أَنَا أَقْرَبُهُمْ نَسَبًا، فَقَالَ: أَدْنُوهُ مِنِّي، وَقَرِّبُوا أَصْحَابَهُ فَاجْعَلُوهُمْ عِنْدَ ظَهْرِهِ، ثُمَّ قَالَ لِتَرْجُمَانِهِ: قُلْ لَهُمْ إِنِّي سَائِلٌ هَذَا عَنْ هَذَا الرَّجُلِ، فَإِنْ كَذَبَنِي فَكَذِّبُوهُ. فَوَاللَّهِ لَوْلاَ الحَيَاءُ مِنْ أَنْ يَأْثِرُوا عَلَيَّ كَذِبًا لَكَذَبْتُ عَنْهُ. ثُمَّ كَانَ أَوَّلَ مَا سَأَلَنِي عَنْهُ أَنْ قَالَ: كَيْفَ نَسَبُهُ فِيكُمْ؟ قُلْتُ: هُوَ فِينَا ذُو نَسَبٍ، قَالَ: فَهَلْ قَالَ هَذَا القَوْلَ مِنْكُمْ أَحَدٌ قَطُّ قَبْلَهُ؟ قُلْتُ: لاَ. قَالَ: فَهَلْ كَانَ مِنْ آبَائِهِ مِنْ مَلِكٍ؟ قُلْتُ: لاَ قَالَ: فَأَشْرَافُ النَّاسِ يَتَّبِعُونَهُ أَمْ ضُعَفَاؤُهُمْ؟ فَقُلْتُ بَلْ ضُعَفَاؤُهُمْ. قَالَ: أَيَزِيدُونَ أَمْ يَنْقُصُونَ؟ قُلْتُ: بَلْ يَزِيدُونَ. قَالَ: فَهَلْ يَرْتَدُّ أَحَدٌ مِنْهُمْ سَخْطَةً لِدِينِهِ بَعْدَ أَنْ يَدْخُلَ فِيهِ؟ قُلْتُ: لاَ. قَالَ: فَهَلْ كُنْتُمْ تَتَّهِمُونَهُ بِالكَذِبِ قَبْلَ أَنْ يَقُولَ مَا قَالَ؟ قُلْتُ: لاَ. قَالَ: فَهَلْ يَغْدِرُ؟ قُلْتُ: لاَ، وَنَحْنُ مِنْهُ فِي مُدَّةٍ لاَ نَدْرِي مَا هُوَ فَاعِلٌ فِيهَا، قَالَ: وَلَمْ تُمْكِنِّي كَلِمَةٌ أُدْخِلُ فِيهَا شَيْئًا غَيْرُ هَذِهِ الكَلِمَةِ، قَالَ: فَهَلْ قَاتَلْتُمُوهُ؟ قُلْتُ: نَعَمْ. قَالَ: فَكَيْفَ كَانَ قِتَالُكُمْ إِيَّاهُ؟ قُلْتُ: الحَرْبُ بَيْنَنَا وَبَيْنَهُ سِجَالٌ، يَنَالُ مِنَّا وَنَنَالُ مِنْهُ. قَالَ: مَاذَا يَأْمُرُكُمْ؟ قُلْتُ: يَقُولُ: اعْبُدُوا اللَّهَ وَحْدَهُ وَلاَ تُشْرِكُوا بِهِ شَيْئًا، وَاتْرُكُوا مَا يَقُولُ آبَاؤُكُمْ، وَيَأْمُرُنَا بِالصَّلاَةِ وَالصِّدْقِ وَالعَفَافِ وَالصِّلَةِ. فَقَالَ لِلتَّرْجُمَانِ: قُلْ لَهُ: سَأَلْتُكَ عَنْ نَسَبِهِ فَذَكَرْتَ أَنَّهُ فِيكُمْ ذُو نَسَبٍ، فَكَذَلِكَ الرُّسُلُ تُبْعَثُ فِي نَسَبِ قَوْمِهَا. وَسَأَلْتُكَ هَلْ قَالَ أَحَدٌ مِنْكُمْ هَذَا القَوْلَ، فَذَكَرْتَ أَنْ لاَ، فَقُلْتُ: لَوْ كَانَ أَحَدٌ قَالَ هَذَا القَوْلَ قَبْلَهُ، لَقُلْتُ رَجُلٌ يَأْتَسِي بِقَوْلٍ قِيلَ قَبْلَهُ. وَسَأَلْتُكَ هَلْ كَانَ مِنْ آبَائِهِ مِنْ مَلِكٍ، فَذَكَرْتَ أَنْ لاَ، قُلْتُ فَلَوْ كَانَ مِنْ آبَائِهِ مِنْ مَلِكٍ، قُلْتُ رَجُلٌ يَطْلُبُ مُلْكَ أَبِيهِ، وَسَأَلْتُكَ، هَلْ كُنْتُمْ تَتَّهِمُونَهُ بِالكَذِبِ قَبْلَ أَنْ يَقُولَ مَا قَالَ، فَذَكَرْتَ أَنْ لاَ، فَقَدْ أَعْرِفُ أَنَّهُ لَمْ يَكُنْ لِيَذَرَ الكَذِبَ عَلَى النَّاسِ وَيَكْذِبَ عَلَى اللَّهِ. وَسَأَلْتُكَ أَشْرَافُ النَّاسِ اتَّبَعُوهُ أَمْ ضُعَفَاؤُهُمْ، فَذَكَرْتَ أَنَّ ضُعَفَاءَهُمُ اتَّبَعُوهُ، وَهُمْ أَتْبَاعُ الرُّسُلِ. وَسَأَلْتُكَ أَيَزِيدُونَ أَمْ يَنْقُصُونَ، فَذَكَرْتَ أَنَّهُمْ يَزِيدُونَ، وَكَذَلِكَ أَمْرُ الإِيمَانِ حَتَّى يَتِمَّ. وَسَأَلْتُكَ أَيَرْتَدُّ أَحَدٌ سَخْطَةً لِدِينِهِ بَعْدَ أَنْ يَدْخُلَ فِيهِ، فَذَكَرْتَ أَنْ لاَ، وَكَذَلِكَ الإِيمَانُ حِينَ تُخَالِطُ بَشَاشَتُهُ القُلُوبَ. وَسَأَلْتُكَ هَلْ يَغْدِرُ، فَذَكَرْتَ أَنْ لاَ، وَكَذَلِكَ الرُّسُلُ لاَ تَغْدِرُ. وَسَأَلْتُكَ بِمَا يَأْمُرُكُمْ، فَذَكَرْتَ أَنَّهُ يَأْمُرُكُمْ أَنْ تَعْبُدُوا اللَّهَ وَلاَ تُشْرِكُوا بِهِ شَيْئًا، وَيَنْهَاكُمْ عَنْ عِبَادَةِ الأَوْثَانِ، وَيَأْمُرُكُمْ بِالصَّلاَةِ وَالصِّدْقِ وَالعَفَافِ، فَإِنْ كَانَ مَا تَقُولُ حَقًّا فَسَيَمْلِكُ مَوْضِعَ قَدَمَيَّ هَاتَيْنِ، وَقَدْ كُنْتُ أَعْلَمُ أَنَّهُ خَارِجٌ، لَمْ أَكُنْ أَظُنُّ أَنَّهُ مِنْكُمْ، فَلَوْ أَنِّي أَعْلَمُ أَنِّي أَخْلُصُ إِلَيْهِ لَتَجَشَّمْتُ لِقَاءَهُ، وَلَوْ كُنْتُ عِنْدَهُ لَغَسَلْتُ عَنْ قَدَمِهِ. ثُمَّ دَعَا بِكِتَابِ رَسُولِ اللَّهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ الَّذِي بَعَثَ بِهِ دِحْيَةُ إِلَى عَظِيمِ بُصْرَى، فَدَفَعَهُ إِلَى هِرَقْلَ، فَقَرَأَهُ فَإِذَا فِيهِ "بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ، مِنْ مُحَمَّدٍ عَبْدِ اللَّهِ وَرَسُولِهِ إِلَى هِرَقْلَ عَظِيمِ الرُّومِ: سَلاَمٌ عَلَى مَنِ اتَّبَعَ الهُدَى، أَمَّا بَعْدُ، فَإِنِّي أَدْعُوكَ بِدِعَايَةِ الإِسْلاَمِ، أَسْلِمْ تَسْلَمْ، يُؤْتِكَ اللَّهُ أَجْرَكَ مَرَّتَيْنِ، فَإِنْ تَوَلَّيْتَ فَإِنَّ عَلَيْكَ إِثْمَ الأَرِيسِيِّينَ" وَ ﴿يَا أَهْلَ الكِتَابِ تَعَالَوْا إِلَى كَلِمَةٍ سَوَاءٍ بَيْنَنَا وَبَيْنَكُمْ أَنْ لاَ نَعْبُدَ إِلَّا اللَّهَ وَلاَ نُشْرِكَ بِهِ شَيْئًا وَلاَ يَتَّخِذَ بَعْضُنَا بَعْضًا أَرْبَابًا مِنْ دُونِ اللَّهِ فَإِنْ تَوَلَّوْا فَقُولُوا اشْهَدُوا بِأَنَّا مُسْلِمُونَ﴾ قَالَ أَبُو سُفْيَانَ: فَلَمَّا قَالَ مَا قَالَ، وَفَرَغَ مِنْ قِرَاءَةِ الكِتَابِ، كَثُرَ عِنْدَهُ الصَّخَبُ وَارْتَفَعَتِ الأَصْوَاتُ وَأُخْرِجْنَا، فَقُلْتُ لِأَصْحَابِي حِينَ أُخْرِجْنَا: لَقَدْ أَمِرَ أَمْرُ ابْنِ أَبِي كَبْشَةَ، أَنَّهُ يَخَافُهُ مَلِكُ بَنِي الأَصْفَرِ. فَمَا زِلْتُ مُوقِنًا أَنَّهُ سَيَظْهَرُ حَتَّى أَدْخَلَ اللَّهُ عَلَيَّ الإِسْلاَمَ. وَكَانَ ابْنُ النَّاظُورِ، صَاحِبُ إِيلِيَاءَ وَهِرَقْلَ، سُقُفًّا عَلَى نَصَارَى الشَّأْمِ يُحَدِّثُ أَنَّ هِرَقْلَ حِينَ قَدِمَ إِيلِيَاءَ، أَصْبَحَ يَوْمًا خَبِيثَ النَّفْسِ، فَقَالَ بَعْضُ بَطَارِقَتِهِ: قَدِ اسْتَنْكَرْنَا هَيْئَتَكَ، قَالَ ابْنُ النَّاظُورِ: وَكَانَ هِرَقْلُ حَزَّاءً يَنْظُرُ فِي النُّجُومِ، فَقَالَ لَهُمْ حِينَ سَأَلُوهُ: إِنِّي رَأَيْتُ اللَّيْلَةَ حِينَ نَظَرْتُ فِي النُّجُومِ مَلِكَ الخِتَانِ قَدْ ظَهَرَ، فَمَنْ يَخْتَتِنُ مِنْ هَذِهِ الأُمَّةِ؟ قَالُوا: لَيْسَ يَخْتَتِنُ إِلَّا اليَهُودُ، فَلاَ يُهِمَّنَّكَ شَأْنُهُمْ، وَاكْتُبْ إِلَى مَدَايِنِ مُلْكِكَ، فَيَقْتُلُوا مَنْ فِيهِمْ مِنَ اليَهُودِ. فَبَيْنَمَا هُمْ عَلَى أَمْرِهِمْ، أُتِيَ هِرَقْلُ بِرَجُلٍ أَرْسَلَ بِهِ مَلِكُ غَسَّانَ يُخْبِرُ عَنْ خَبَرِ رَسُولِ اللَّهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ، فَلَمَّا اسْتَخْبَرَهُ هِرَقْلُ قَالَ: اذْهَبُوا فَانْظُرُوا أَمُخْتَتِنٌ هُوَ أَمْ لاَ، فَنَظَرُوا إِلَيْهِ، فَحَدَّثُوهُ أَنَّهُ مُخْتَتِنٌ، وَسَأَلَهُ عَنِ العَرَبِ، فَقَالَ: هُمْ يَخْتَتِنُونَ، فَقَالَ هِرَقْلُ: هَذَا مُلْكُ هَذِهِ الأُمَّةِ قَدْ ظَهَرَ. ثُمَّ كَتَبَ هِرَقْلُ إِلَى صَاحِبٍ لَهُ بِرُومِيَةَ، وَكَانَ نَظِيرَهُ فِي العِلْمِ، وَسَارَ هِرَقْلُ إِلَى حِمْصَ، فَلَمْ يَرِمْ حِمْصَ حَتَّى أَتَاهُ كِتَابٌ مِنْ صَاحِبِهِ يُوَافِقُ رَأْيَ هِرَقْلَ عَلَى خُرُوجِ النَّبِيِّ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ، وَأَنَّهُ نَبِيٌّ، فَأَذِنَ هِرَقْلُ لِعُظَمَاءِ الرُّومِ فِي دَسْكَرَةٍ لَهُ بِحِمْصَ، ثُمَّ أَمَرَ بِأَبْوَابِهَا فَغُلِّقَتْ، ثُمَّ اطَّلَعَ فَقَالَ: يَا مَعْشَرَ الرُّومِ، هَلْ لَكُمْ فِي الفَلاَحِ وَالرُّشْدِ، وَأَنْ يَثْبُتَ مُلْكُكُمْ، فَتُبَايِعُوا هَذَا النَّبِيَّ؟ فَحَاصُوا حَيْصَةَ حُمُرِ الوَحْشِ إِلَى الأَبْوَابِ، فَوَجَدُوهَا قَدْ غُلِّقَتْ، فَلَمَّا رَأَى هِرَقْلُ نَفْرَتَهُمْ، وَأَيِسَ مِنَ الإِيمَانِ، قَالَ: رُدُّوهُمْ عَلَيَّ، وَقَالَ: إِنِّي قُلْتُ مَقَالَتِي آنِفًا أَخْتَبِرُ بِهَا شِدَّتَكُمْ عَلَى دِينِكُمْ، فَقَدْ رَأَيْتُ، فَسَجَدُوا لَهُ وَرَضُوا عَنْهُ، فَكَانَ ذَلِكَ آخِرَ شَأْنِ هِرَقْلَ رَوَاهُ صَالِحُ بْنُ كَيْسَانَ، وَيُونُسُ، وَمَعْمَرٌ، عَنِ الزُّهْرِيِّ.', NULL, NULL, NULL, 'Révélation, croyance');
INSERT INTO hadiths (id, sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (9, 'Exemption de Allah', 'Al-Bukhari', NULL, 'Sahih', ' كان الله و لم يكن شىء غيره', NULL, NULL, NULL, 'exemption, croyance');
INSERT INTO hadiths (id, sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (10, 'Exemption de Allah', 'Al-Bukhari', NULL, 'Sahih', 'كَانَ اللهُ وَلَمْ يَكُنْ شَىءٌ غَيْرُهُ ', 'Dieu existe de toute éternité et rien d’autre que Lui n’est de toute éternité', 'Kāna l-Lāhou wa lam yakou, chay’oun ghayrouh', NULL, 'exemption, croyance');
INSERT INTO hadiths (id, sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (11, 'Croyance', 'Al-Bukhari', NULL, 'Sahih', ' فَإِنَّ اللهَ حَرَّمَ عَلَى النارِ – أَيِ الدَّوامَ فِيها لِلْأَبَدِ – مَنْ قالَ لَا إِلَهَ إِلَّا اللهُ يَبْتَغِي بِذَلِكَ وَجْهَ اللهِ ', 'Certes Dieu a voulu que ne reste pas éternellement en enfer celui qui aura dit : لا إله إلَّا الله –Il n’est de dieu que Dieu– en recherchant par cela l’agrément de Dieu » c’est-à-dire en ayant cela pour croyance dans son cœur et en cherchant par cela à se rapprocher de l’agrément de Dieu et non pas par hypocrisie.', 'fa’inna l-Laha harrama ^ala n-nar –‘ayi d-dawama fiha lil-‘abad– man qala la ‘ilaha ‘il-la l-Lahou yabtaghi bidhalika wajha l-Lah', 'Ce حديث hadith honoré et d’autres indiquent que celui qui dit les deux témoignages en croyant et en acceptant leur signification, et qui meurt sur cela, nécessairement, il entrera au Paradis même s’il est châtié avant cela à cause de ses péchés si Dieu ne lui pardonne pas. Ceci est par la grâce et le mérite que Dieu a sur Ses esclaves et cela indique que le plus éminent des droits que Dieu a sur Ses esclaves, c’est le توحيد tawhid –la croyance en Son unicité– c’est-à-dire de ne pas Lui associer quoi que ce soit, et de croire en la véracité de Son Messager صَلَّى اللهُ عَلَيْهِ وسَلَّم.', 'enfer, croyance');
INSERT INTO hadiths (id, sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (12, 'Exemption de Allah', 'Al-Bukhari', NULL, 'Sahih', 'يَخْرُجُ مِنَ النّارِ مَنْ قالَ لَا إِلَهَ إِلَّا اللهُ وَفِي قَلْبِهِ وَزْنُ ذَرَّةٍ مِنْ إِيمانٍ', 'Sortira de l’enfer quiconque a dit : لا إله إلَّا الله –Il n’est de dieu que Dieu– en ayant dans son cœur le minimum de la foi.', 'yakhroujou mina n-nar man qala la ‘ilaha ‘il-la l-lah wafi qalbihi waznou dharratin min ‘iman', NULL, 'exemption, croyance');
INSERT INTO hadiths (id, sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (13, 'tawhid', 'Imam Malik', NULL, 'Sahih', 'أَفْضَلُ ما قُلْتُ أَنَا وَالنَّبِيُّونَ مِنْ قَبْلِي لا إِلَهَ إِلَّا اللهُ', ' La meilleure des paroles que j’ai dite, moi ainsi que les prophètes qui m’ont précédé c’est لاَ إِلَهَ إِلَّا الله –Il n’est de dieu que Dieu–.', '‘afdalou ma qoultou ‘ana wan-nabiyyouna min qabli la ‘ilaha ‘il-la l-Lah', 'Rapporté dans Al-Mouwatta ', 'parole, croyance, tawhid');
INSERT INTO hadiths (id, sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (14, 'Attributs de Allah', 'Abu Dawoud', NULL, NULL, 'ما شاءَ اللهُ كانَ وما لَمْ يَشَأْ لَمْ يَكُنْ', 'Ce que Dieu veut est, et ce qu’Il ne veut pas n’est pas', 'ma cha’a l-Lahou kana wama lam yacha’ lam yakoun', 'Tout ce qui entre en existence comme bien et comme mal, comme obéissance et comme désobéissance, comme grâce et comme épreuve, tout cela existe par la volonté de Dieu et par Sa prédestination. Il n’advient aucun changement ni aucune modification dans Sa volonté. La volonté de Dieu, chers frères de foi, comme tous les attributs de Dieu, ne change pas, car le changement fait partie des caractéristiques des créatures, des signes de ce qui entre en existence.', 'parole, croyance, attributs');
INSERT INTO hadiths (id, sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (15, 'Mécréance', 'At-Tirmidhiyy', NULL, NULL, 'إِنَّ العَبْدَ لَيَتَكَلَّمُ بِالكَلِمَةِ لاَ يَرَى بِهَا بَأْسًا يَهْوِي بِهَا فِي النّارِ سَبْعِينَ خَرِيفًا', 'Certes, il arrive que quelqu’un dise une parole dans laquelle il ne voit pas de mal, mais à cause de laquelle il chutera en enfer pendant soixante-dix automnes.', '‘inna l-^abda layatakallamou bil-kalimati la yara biha ba’sa yahwi biha fi n-nari sab^ina kharifa', 'Le Messager de Dieu صلَّى الله عليه وسلم a donc indiqué dans ce حديث hadith qu’il est possible que quelqu’un dise une parole qu’il ne voit pas comme étant nuisible pour lui-même, mais qui le fera chuter pendant soixante-dix ans en enfer, du fait que sa parole était de la mécréance, s’il ne revient pas à l’Islam. Il est rapporté du Prophète صلَّى الله عليه وسلم que le fond de l’enfer est à une distance de soixante-dix ans de chute et que cet endroit ne sera atteint que par les mécréants.', 'mécréance, apostasie, enfer');
INSERT INTO hadiths (id, sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (16, 'Attributs de Allah', 'Al-Bayhaqiyy', NULL, NULL, 'أَنْتَ الظَّاهِرُ فَلَيْسَ فَوْقَكَ شَىْءٌ وَأَنْتَ البَاطِنُ فَلَيْسَ دُونَكَ شَىْءٌ ', 'Tu es الظَّاهِر Adh–Dhahir, rien n’est donc au-dessus de Toi et Tu es البَاطِن Al-Batin, rien n’est donc en dessous de Toi.', '‘anta dh–Dhahirou falayça fawqaka chay’ wa’anta l-Batinou falayça dounaka chay’', 'Le Hafidh Al-Bayhaqiyy a dit dans son livre Al-‘Asma’ou was–Sifat : « Certains de nos compagnons –parmi les savants chaféites acharites–, ont tiré argument, pour nier l’endroit au sujet de Dieu, de la parole du Prophète صلَّى الله عليه وسلم l-Bayhaqiyy a dit : « Puisque rien n’est au-dessus de Lui et que rien n’est en dessous de Lui, Il n’est donc pas dans un endroit. » Et c’est quelque chose d’extrêmement clair et évident, comme le soleil en plein jour.', 'attributs, exemption');
INSERT INTO hadiths (id, sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (17, 'Croyance', 'Ibnou Hibban', NULL, 'Sahih', 'وَيْلٌ لِمَنْ قَرَأَهَا وَلَمْ يَتَفَكَّرْ فِيها', 'Malheur à celui qui récite ce verset et ne médite pas dessus.', '‘anta dh–Dhahirou falayça fawqaka chay’ wa’anta l-Batinou falayça dounaka chay’', ' En effet, il a été rapporté du Messager de Dieu صلَّى الله عليه وسلم qu’il a dit au sujet du verset:  إِنَّ فِي خَلۡقِ ٱلسَّمَٰوَٰتِ وَٱلۡأَرۡضِ وَٱخۡتِلَٰفِ ٱلَّيۡلِ وَٱلنَّهَارِ لَأٓيَٰتٖ لِّأُوْلِي ٱلۡأَلۡبَٰبِ ٱلَّذِينَ يَذۡكُرُونَ ٱللَّهَ قِيَٰمٗا وَقُعُودٗا وَعَلَىٰ جُنُوبِهِمۡ وَيَتَفَكَّرُونَ فِي خَلۡقِ ٱلسَّمَٰوَٰتِ وَٱلۡأَرۡضِ رَبَّنَا مَا خَلَقۡتَ هَٰذَا بَٰطِلٗا سُبۡحَٰنَكَ فَقِنَا عَذَابَ ٱلنَّارِ Certes, la méditation au sujet des créatures de Dieu mène à la connaissance de l’existence du Créateur et de Son unicité. Les savants de Ahlou s-Sounnah ont dit qu’il est un devoir, pour toute personne responsable, d’avoir dans le cœur une preuve globale de l’existence de Dieu.', 'meditation, croyance');
INSERT INTO hadiths (id, sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (18, 'Tombe', 'At-Tirmidhiyy', NULL, NULL, ' القَبْرُ رَوضةٌ مِن رِياضِ الجنّةِ أو حُفرةٌ مِن حُفَرِ النَّارِ', ' La tombe peut être comme l’un des jardins du Paradis ou comme l’un des antres de l’enfer.', 'al-qabrou rawdatoun min riyadi l-jannati ‘aw houfratoun min houfari n-nar', NULL, 'tombe, chatîment');
INSERT INTO hadiths (id, sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (19, 'Tombe', 'At-Tirmidhiyy', NULL, NULL, ' نعم عَذابُ القَبرِ حَقٌّ', 'Oui, le supplice de la tombe est une vérité.', 'na^am ^adhabou l-qabri haqq', 'Et dans les Sounan de An-Naça’iyy d’après ^A’ichah, que Dieu l’agrée, elle a dit : « J’ai interrogé le Messager de Dieu صلَّى الله عليه وسلم au sujet du supplice de la tombe et il a répondu :', 'tombe, chatîment');
INSERT INTO hadiths (id, sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (20, 'Tombe', 'At-Tirmidhiyy', NULL, NULL, 'أَتُـرَدُّ عَلَيْنَا عُقولُنا يا رسولَ الله ؟  نَعَم كهَيْئَتِكمُ اليَوم', ' Est ce que nous reprendrons conscience, ô Messager de Dieu ? » Le Prophète lui avait répondu : Oui, tout comme vous êtes conscients aujourd’hui.', '‘atouraddou ^alayna ^ouqoulouna ya Raçoula l-Lah ? na^am kahay’atikoumou l-yawm', ' c’est ce qui est rapporté de notre maître ^Oumar Ibnou l-Khattab que Dieu l’agrée, lorsqu’il avait interrogé le Bien-aimé. Celui qui a rapporté le حديث hadith a dit que ^Oumar s’est alors tu et qu’il n’a pas fait de commentaire, puisqu’il avait entendu une information qu’il ne connaissait pas auparavant.', 'tombe, chatîment');
INSERT INTO hadiths (id, sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (21, 'Tombe', 'At-Tirmidhiyy', NULL, NULL, 'فأَكْثِرُوا مِنْ ذِكْرِ هَاذِمِ اللَّذَّاتِ الْمَوْتِ فَإِنَّهُ لَمْ يَأْتِ عَلَى القَبْرِ يَوْمٌ إِلاَّ تَكَلَّمَ فِيهِ فَيَقُولُ أَنَا بَيْتُ الغُرْبَةِ وَأَنَا بَيْتُ الوَحْدَةِ وَأَنَا بَيْتُ التُّرَابِ وَأَنَا بَيْتُ الدُّودِ فَإِذَا دُفِنَ العَبْدُ الْمُؤْمِنُ أيِ الكامِلُ قَالَ لَهُ القَبْرُ مَرْحَبًا وَأَهْلًا أَمَا إِنْ كُنْتَ لأَحَبَّ مَنْ يَمْشِى عَلَى ظهري إِلَىَّ فَإِذْ وُلِّيتُكَ اليَوْمَ وَصِرْتَ إِلَىَّ فَسَتَرَى صَنِيعِي بِكَ قَالَ فَيَتَّسِعُ لَهُ مَدَّ بَصَرِهِ وَيُفْتَحُ لَهُ بابٌ إِلَى الْجَنَّةِ وَإِذَا دُفِنَ العَبْدُ الفَاجِرُ أَوِ الكَافِرُ قَالَ لَهُ القَبْرُ لا مَرْحَبًا ولا أَهْلًا أَمَا إِنْ كُنْتَ لَأَبْغَضَ مَنْ يَمْشِى عَلَى ظهري إِلَىَّ فَإِذْ وُلِّيتُكَ اليَوْمَ وصِرْتَ إِلَىَّ فَسَتَرَى صَنِيعِي بِكَ قَالَ فَيَلْتَئِمُ عَلَيْهِ حَتَّى تَلْتَقِى عَلَيْهِ وَتَخْتَلِفَ أَضْلاعُهُ قَالَ – أي الرَّاوِي – قالَ رَسُولُ اللهِ صَلَّى اللهُ عليه وسلَّمَ بِأَصَابِعِهِ فَأَدْخَلَ بَعْضَهَا فِي جَوْفِ بَعْضٍ قَالَ وَيُقَيِّضُ اللهُ لَهُ سَبْعِينَ تِنِّينًا لَوْ أَنَّ وَاحِدًا مِنْهَا نَفَخَ فِي الأَرْضِ مَا أَنْبَتَتْ شَيْئًا مَا بَقِيَتِ الدُّنْيَا فَيَنْهَشْنَهُ ويَخْدِشْنَهُ حَتَّى يُفْضَى بِهِ إِلَى الحِسَابِ', ' Rappelez-vous souvent de celle qui détruit les plaisirs, à savoir la mort, parce qu’il n’y a pas un jour sans que la tombe dise : “Je suis la demeure de l’exil, je suis la demeure de la solitude, je suis la demeure de la terre, je suis la demeure des vers !” Lorsqu’un esclave croyant –c’est-à-dire dont la foi était complète– est enterré, la tombe lui dit : “Bienvenue ! Tu étais de ceux que j’aimais le plus quand tu marchais à la surface, et maintenant que tu es à ma charge et que tu es parvenu chez moi, tu verras comment j’agis avec toi.” La tombe s’étend pour lui à perte de vue. Il lui est ouvert une porte qui donne sur le Paradis. Alors que lorsqu’un esclave pervers ou non-croyant est enterré, la tombe lui dit : “Tu n’es pas le bienvenu ! Tu faisais partie de ceux que je détestais le plus quand tu marchais à la surface, et maintenant que tu es à ma charge et que tu es arrivé chez moi, tu vas voir ce que je fais de toi !“ Alors la tombe se referme en faisant pression sur lui au point que ses côtes s’entrecroisent. Celui qui rapporte le حديث hadith a dit : Le Messager de Dieu a montré ses doigts et les a fait entrer les uns dans les autres, et il a dit ce qui signifie : « Dieu met à sa charge soixante-dix serpents, si l’un d’entre eux soufflait sur la terre, elle ne ferait plus rien pousser jusqu’à la fin du bas monde. Ils vont le dévorer et l’écorcher jusqu’à ce qu’il parvienne au Jour de l’exposition des actes.', NULL, ' c’est ce qui est rapporté de notre maître ^Oumar Ibnou l-Khattab que Dieu l’agrée, lorsqu’il avait interrogé le Bien-aimé. Celui qui a rapporté le حديث hadith a dit que ^Oumar s’est alors tu et qu’il n’a pas fait de commentaire, puisqu’il avait entendu une information qu’il ne connaissait pas auparavant.', 'tombe, chatîment');
INSERT INTO hadiths (id, sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (22, 'Tombe', 'At-Tirmidhiyy', NULL, NULL, '.ارْقُدْ مَنْهُوشًا، فَمَا مِنْ دَابَّةٍ فِى الأَرْضِ إِلَّا ولَها فِى جَسَدِهِ نَصِيبٌ', 'Reste ! Tu seras atterré et mordu. Il n’y aura pas un animal sous terre sans qu’il n’ait une part de son corps', '‘ourqoud manhoucha fama min dabbatin fi l-‘ardi ‘il-la walaha fi jaçadihi nasib', 'Et dans les Sounan de An-Naça’iyy d’après ^A’ichah, que Dieu l’agrée, elle a dit : « J’ai interrogé le Messager de Dieu صلَّى الله عليه وسلم au sujet du supplice de la tombe et il a répondu :', 'tombe, chatîment');
INSERT INTO hadiths (id, sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (23, 'Tombe', 'At–Tabaraniyy', NULL, NULL, ' ويُسَلَّطُ عَلَيْهِ عَقَارِبُ وثَعَابِينُ، لَوْ نَفَخَ أَحَدُهُمْ فِي الدُّنْيَا ما أَنْبَتَتْ شَيْئًا تَنْهَشُهُ وتُؤْمَرُ الأَرْضُ فَتُضَمُّ حَتَّى تَخْتَلِفَ أَضْلاعُهُ', 'Il sera assailli par des scorpions et des serpents ; si l’un d’entre eux soufflait sur le bas monde, il n’y pousserait plus rien. Ils le mordront. Et on ordonnera à la terre de se resserrer jusqu’à ce que ses côtes s’entrecroisent.', 'wayouçallatou ^alayhi ^aqaribou watha^abinou law nafakha ‘ahadouhoum fi d-dounya ma ‘anbatat chay’an tanhachouhou watou’marou l-‘ardou fatoudammou hatta takhtalifa ‘adla^ouh', 'Et dans les Sounan de An-Naça’iyy d’après ^A’ichah, que Dieu l’agrée, elle a dit : « J’ai interrogé le Messager de Dieu صلَّى الله عليه وسلم au sujet du supplice de la tombe et il a répondu :', 'tombe, chatîment');
INSERT INTO hadiths (id, sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (24, 'Tombe', 'Abou Dawoud', 'Al-Bara’ Ibnou ^Azib', NULL, ' استَعِيذوا باللهِ مِن عَذابِ القَبر، استَعِيذوا باللهِ مِن عَذابِ القَبر ', 'Demandez à Dieu la préservation du supplice de la tombe ! Demandez à Dieu la préservation du supplice la tombe ! à réciter 2 ou 3 fois', '‘ista^idhou bil-Lah min ^adhabi l-qabr, ‘ista^idhou bil-Lah min ^adhabi l-qabr', 'Abou Dawoud a rapporté dans ses Sounan d’après Al-Bara’ Ibnou ^Azib, qu’il a dit : « Nous étions sortis avec le Messager de Dieu صلَّى الله عليه وسلم dans le convoi funéraire d’un homme des ‘Ansar –les partisans–. Nous étions arrivés auprès de la tombe après qu’il avait été enterré. Le Messager de Dieu صلَّى الله عليه وسلم s’est assis et nous avions pris place autour de lui, comme si nous avions des oiseaux qui s’étaient posés sur nos têtes. Nous étions immobiles. Il tenait dans sa main une branche avec laquelle il tapait la terre, il a relevé la tête et a dit :', 'tombe, chatîment');
INSERT INTO hadiths (id, sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (25, 'Science', 'Al-Bayhaqiyy', 'hafidh Al-Mizziyy', 'haçan', ' طَلَبُ العِلْمِ فَرِيضَةٌ على كُلِّ مُسْلِم', 'Quérir la science de la religion est une obligation pour tout musulman', '‘talabou l-^ilmi faridatoun ^ala koulli mouslim', 'c’est-à-dire « pour tout musulman et toute musulmane ».', 'science, apprentissage');
INSERT INTO hadiths (id, sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (26, 'Science', 'Al-Boukhariyy', NULL, 'Sahih', '  مَنْ يُرِد اللهُ به خَيْرًا يُفَقِّهْهُ في الدِّينِ إِنمَّا العِلْمُ بالتَّعَلُّمِ والْفِقْهُ بالتَّفَقُّهِ', ' Celui pour qui Allāh veut le bien, Il lui facilite l’apprentissage de la religion certes la science de la religion s’acquiert par transmission orale', 'man youridi l-Lahou bihi khayra youfaqqih-hou fi d-din,, ’inamma l-`ilmou bi t-ta`alloumi wa l-fiqhou bi t-tafaqqouhi', NULL, 'science, apprentissage');
INSERT INTO hadiths (id, sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (27, 'Science', 'Abôu dharr', NULL, 'Sahih', 'إنَّ حُضور مجلس علم أفضل من صلاة ألف ركعة ', 'Assister à une assemblée de science de la religion est mieux que d’accomplir mille rak`ah des prières surérogatoires', '‘inna ḥouḍôura majlisi `ilmin ‘afḍalou min ṣalâti ‘alfi rak`ah', NULL, 'science, apprentissage');
INSERT INTO hadiths (id, sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (28, 'Science', 'Al-Boukhâriyy', NULL, 'Sahih', 'بَلِّغوا عَنِّي وَلَوْ ءَايَةً', 'Transmettez de moi ne serait-ce qu’une ‘âyah', NULL, NULL, 'science, apprentissage');
INSERT INTO hadiths (id, sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (29, 'Science', 'at-tirmîdhiyy', NULL, 'Sahih', 'لا يشبعُ مؤمنٌ مِنْ خيرٍ حتى يكونَ مُنتهاهُ الجنّة', 'le croyant ne se rassasie pas d’un bien jusqu’à ce que sa fin soit le paradis', NULL, NULL, 'science, apprentissage');
INSERT INTO hadiths (id, sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (30, 'Science', 'at-tirmîdhiyy', NULL, 'Sahih', 'روى الترمذي وغيره “أن رسول الله صلى الله عليه وسلم دخل المسجد، فدخل رجل فصلى ثم جاء فسلم على النبي صلى الله عليه وسلم، فرد عليه السلام فقال : ارجع فصل فإنك لم تصل، فرجع الرجل فصلى كما كان صلى ثم جاء إلى النبي صلى الله عليه وسلم فسلم عليه، فرد عليه فقال له : ارجع فصل فإنك لم تصل، حتى فعل ذلك ثلاث مرات فقال له الرجل: والذي بعثك بالحق ما أحسن غير هذا، فعلمني ” فعلّمه الرسول صلى الله عليه الصلاة وسلم', NULL, NULL, 'Le Prophète صلى الله عليه وسلّم nous a appris que l’intention à elle seule n’est pas suffisante. Le ḥadīth rapporté par At-Tirmîdhiyy ainsi que d’autres en est la preuve: Le sens de ce hadith est que le Messager est entré dans la mosquée, puis un homme est entré et a effectué la prière. Ensuite cet homme est venu et a passé le salam au Prophète. Le Prophète a répondu au salam puis a dit : (’irji` faṣalli fa’innaka lam touṣalli) ce qui signifie « Retourne et prie car tu n’as pas prié ». L’homme est retourné et a prié de la même manière que la première fois. Puis il est revenu et a de nouveau passé le salam au Prophète . Le Prophète a répondu au salâm puis a dit : (’irji` faṣalli fa’innaka lam touṣalli) ce qui signifie « Retourne et prie car tu n’as pas prié ». Ainsi l’homme est retourné prier. Cette scène s’est reproduite trois fois. L’homme a alors dit : « Par Celui Qui t’a envoyé avec la vérité, je ne connais pas autre que cela, apprends-moi. » Le Messager lui a alors appris comment prier. ', 'science, apprentissage, intention');
INSERT INTO hadiths (id, sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (31, 'Science', 'ibnou Ḥibbân', NULL, 'Sahih', 'رُبَّ قائم ليس له من قيامه إلا السهر، ورُبَّ صائم ليس له من صيامه إلا الجوع والعطش', 'l se peut que quelqu’un pense faire des prières surérogatoires de nuit et il ne gagne de cela que la veille et il se peut que quelqu’un pense faire le jeûne et il ne gagne de cela que que la faim et la soif', NULL, 'C’est à dire que cette personne a fait des actes qui n’étaient pas valables du fait qu’il manque des conditions de validité ou des piliers, ou elle a fait des actes qui ne remplissent pas les conditions pour être récompensés. On apprend de ces ḥadīth qu’il ne suffit pas d’avoir une bonne intention, de vouloir faire le bien, pour qu’un acte d’adoration soit valable. En effet, il faut que l’acte soit conforme à l’enseignement du Prophète. Il est donc primordial d’apprendre les lois de la religion.', 'science, apprentissage');
INSERT INTO hadiths (id, sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (32, 'Science', 'Al-Bayhaqiyy', NULL, 'Sahih', 'طَلَبُ العِلْمِ فَرِيضَةٌ عَلى كُلِّ مُسْلِمٍ', 'Rechercher la science est une obligation pour tout musulman', 'talabou l-`ilmi farîḍatoun `alâ koulli mouslim', 'c’est-à-dire que demander la science de la religion est une obligation pour tout musulman responsable. Ainsi il est un devoir d’apprendre tous les sujets de la religion dont on a besoin au quotidien, tels que la croyance en Dieu, la croyance en les Prophètes, ce qui fait sortir de l’Islam, les lois de la purification et de la prière, les lois du jeûne…Le musulman ne peut pas se contenter d’imiter les actes faits par d’autres musulmans que ce soit pour la prière ou autre. Même si la personne a une intention sincère, ce n’est pas suffisant. Il faut que l’acte soit en conformité avec les lois de la religion. Il est donc nécessaire d’apprendre quels sont les piliers de cet acte d’adoration, ses conditions de validité, ce qui l’annule…', 'science, apprentissage');
INSERT INTO hadiths (id, sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (33, 'Science', 'Abôu dharr', NULL, 'Sahih', 'لَأَنْ يَتَعَلَّمَ أَحَدُكُمْ بَابًا مِنَ العِلْمِ أَو يُعَلِّمَهُ خَيْرٌ لَهُ مِنْ صَلاةِ ألْفِ رَكْعَةٍ', 'Que l’un de vous apprenne un chapitre de la religion ou l’enseigne aura plus de récompenses que de prier mille rak`ah des prières surérogatoires ', 'la’an yata`allama ‘aḥadoukoum bâban min l-`ilmi ‘aw you`allimahou khayroun lahou min ṣalâti ‘alfi rak`ah', NULL, 'science, apprentissage');
INSERT INTO hadiths (id, sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (34, 'Science', 'Ibnou Mâjah', NULL, 'Haçan', 'يَا أبا ذَر لأن تَغدُوَ فَتَتَعَلَّمَ ءايَة مِن كِتَاب الله خَيْرٌ لَكَ مِن أَن تُصَلّيَ مِائةَ رَكْعَةٍ ولأن تَغدُوَ فَتَتَعَلَّمَ بَاباً مِن العِلمِ خَيْرٌ لَكَ مِن أَن تُصَلّيَ أَلفَ رَكْعَةٍ', ' Ô Abôu Dhar si tu te déplaces et tu apprends une ‘Ayah du Qour’ân tu seras plus récompensé que si tu priais cent rak`ah (des prières surérogatoires) et si tu te déplaces et tu apprends un chapitre de la religion tu seras plus récompensé que si tu priais mille rak`ah (des prières surérogatoires)', 'man youridi l-Lahou bihi khayra youfaqqih-hou fi d-din', NULL, 'science, apprentissage');
INSERT INTO hadiths (id, sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (35, 'Comportement', 'At- Tirmidhiyy', NULL, 'Sahih', 'إِنَّ الدَّالَ عَلَى الخَيْرِ كَفَاعِلِهِ', 'Celui qui indique le bien aux autres est comme celui qui le fait. ', '‘inna d-dala ^ala l-khayri kafa^ilih', 'C’est-à-dire qu’il aura une récompense semblable à la récompense de celui qui le fait', 'comportement, apprentissage');
INSERT INTO hadiths (id, sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (36, 'Purification, Ablutions', 'Abou Hourayrah', 'An-Naça’iyy', 'Sahih', ' إِذَا تَوَضَّأْتُمْ فَابْدَءُوا بِمَيَامِنِكُمْ', 'Quand vous faites le woudou’, commencez par le côté droit. ', '‘idha tawadda’toum fabda’ou bimayaminikoum', NULL, 'Purification, Ablutions');
INSERT INTO hadiths (id, sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (37, 'Purification, Ablutions', '^Oumar', NULL, NULL, ' مَنْ تَوَضَّأَ فَأَحْسَنَ الوُضُوءَ ثُمَّ قَالَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللهُ وَحْدَهُ لَا شَرِيكَ لَهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ اللَّهُمَّ اجْعَلْنِي مِنَ التَّوَّابِينَ وَاجْعَلْنِي مِنَ المُتَطَهِّرِينَ فُتِحَتْ لَهُ ثَمَانِيَةُ أَبْوَابِ الجَنَّةِِ يَدْخُلُ مِنْ أَيِّهَا شَاءَ', NULL, NULL, 'Celui qui fait son woudou’ tout en s’appliquant à le faire parfaitement, puis qui dit : (‘Ach-hadou ‘an la ‘ilaha ‘il-la l-Lah wahdahou la charika lah wa‘ach-hadou ‘anna Mouhammadan ^abdouhou waraçoulouh Allahoumma j^alni mina t-tawwabina waj^alni mina l-moutatahhirin) –je témoigne qu’il n’est de dieu que Dieu, qu’Il est le dieu unique et qu’Il n’a pas d’associé ; et je témoigne que محمد Mouhammad est Son esclave et Son messager, ô Dieu, fais que je sois au nombre de ceux qui se repentent et au nombre de ceux qui se purifient–, les huit portes du Paradis lui seront ouvertes, et il entrera au Paradis par la porte qu’il voudra.', 'Purification, Ablutions');
INSERT INTO hadiths (id, sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (38, 'Purification, Ablutions', NULL, NULL, NULL, ' مَنْ تَوَضَّأَ كَمَا أُمِرَ وَصَّلى كَمَا أُمِرَ غَفَرَ اللهُ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ ', 'Celui qui fait le woudou’ comme il en a reçu l’ordre et qui fait la prière comme il en a reçu l’ordre, Dieu lui pardonnera ses péchés antérieurs.', 'man tawadda’a kama ‘oumira wa salla kama ‘oumira ghafara l-Lahou lahou ma taqaddama min dhanbih', 'Il s’agit ici des petits péchés', 'Purification, Ablutions');
INSERT INTO hadiths (id, sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (39, 'Purification, Ablutions', NULL, NULL, NULL, ' مَنْ تَوَضَّأَ كَمَا أُمِرَ وَصَّلى كَمَا أُمِرَ غَفَرَ اللهُ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ ', 'Celui qui fait le woudou’ comme il en a reçu l’ordre et qui fait la prière comme il en a reçu l’ordre, Dieu lui pardonnera ses péchés antérieurs.', 'man tawadda’a kama ‘oumira wa salla kama ‘oumira ghafara l-Lahou lahou ma taqaddama min dhanbih', 'Il s’agit ici des petits péchés', 'Purification, Ablutions');
INSERT INTO hadiths (id, sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (40, 'Repentir', NULL, NULL, NULL, 'التَّائِبُ مِنَ الذَّنْبِ كَمَنْ لاَ ذَنْبَ لَهُ', 'Celui qui se repent d’un péché, c’est comme s’il ne l’avait pas commis', 'at-tā’ibou mina l-ladhinbi kaman lā dhanbha lah', NULL, 'Repentir');
INSERT INTO hadiths (id, sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (41, 'Oeuvres', 'Al-Boukhāriyy', NULL, NULL, ' أَفْضَلُ الأَعْمَالِ إِيمانٌ بِاللهِ ورَسُولِهِ', ' La meilleure des œuvres est la croyance en Allāh et en Son Messager', '’afḍalou l-’a`māli ’īmānoun bi l-Lāhi wa raçoūlih', 'Il s’agit ici des petits péchés', 'Oeuvres');
INSERT INTO hadiths (id, sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (42, 'Foi', NULL, NULL, NULL, 'وَأَمَّا الْكَافِرُ فَيُطْعَمُ بِحَسَنَاتِهِ في الدُّنْيَا حَتّى إِذا أَفْضَى إِلى الآخِرَةِ لَم يَكُنْ لَهُ مِنْهَا نَصِيبٌ', ' Quant au non-croyant il sera rétribué pour ses bonnes œuvres dans cette vie, mais dans l’au-delà il n’aura aucune récompense', 'wa ’amma l-kāfirou fayouṭ`amou biḥasanātihi fi d-dounyā ḥattā ’idhā ’afḍā ’ila l-’ākhirah lam yakoun lahou minhā naṣīb', 'Il s’agit ici des petits péchés', 'Foi, Croyance');
INSERT INTO hadiths (id, sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (43, 'Foi', 'Mouslim', NULL, 'Sahih', 'أَنْ تُؤْمِنَ باللهِ وَمَلائِكَتِهِ وَكُتِبِهِ ورُسُلِهِ والْيَوْمِ الآخِرِ وتُؤْمِنَ بالْقَدَرِ خَيْرِهِ وَشَرِّهِ', '  La foi est que tu crois en Allāh, en Ses Anges, en Ses Livres, en Ses Prophètes, en Le Jour Dernier et que tu crois que Dieu a prédestiné le bien et le mal', '’an tou’mina bi l-Lāhi wa malā’ikatihi wa koutoubihi wa rouçoulihi wa l-yawmi l-’ākhiri wa tou’mina bi l-qadari khayrihi wa charrih', 'La croyance est telle que l’a expliqué le Prophète Mouḥammad ṣalla l-Lāhou `alayhi wa sallam, lorsqu’il a été interrogé sur la foi, il a dit:', 'Foi, Croyance');
INSERT INTO hadiths (id, sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (44, 'Prophètes', 'Al-Boukhāriyy', NULL, 'Sahih', 'الأَنْبِيَاءُ إِخْوَةٌ لِعَلاّتٍ دِينُهُم وَاحِد وَأُمَّهَاتُهُم شَتَّى', 'Les Prophètes sont comme des frères du même père, leur religion est la même et leurs lois diffèrent', 'Al ‘anbiyā’ou ‘ikhwatoun li`allāt dīnouhoum wāḥid wa ‘oummahātouhoum chattā', 'Le prophète Mouḥammad a assimilé les prophètes à des frères du même père du fait que leur religion est la même, que leur croyance est unique, ils ont appelé à la religion de l’Islam, et les lois des prophètes messagers diffèrent. La Loi comprend les jugements qui concernent les pratiques, telles que la zakat, la prière et ce qui est du même genre. Et la Loi du prophète Mouḥammad est la meilleure Loi et la plus facile. Et ce changement dans la Loi a lieu selon une sagesse, et Dieu sait ce qui est de l’intérêt des esclaves mieux qu’eux.', 'Foi, Croyance, Prophètes');
INSERT INTO hadiths (id, sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (45, 'Prophètes', NULL, NULL, NULL, ' أَفْضَلُ مَا قُلْتُ أَنَا وَالنَّبِيُّونَ مِنْ قَبْلِي لاَ إِلَهَ إِلاَّ الله وَحْدَهُ لاَ شَرِيكَ لَهُ ', 'La meilleure des choses que j’ai dite ainsi que les Prophètes qui m’ont précédé c’est : Lā ilāha illa l-Lāhou waḥdahou lā charīka lah ; Il n’est de dieu que Dieu, l’Unique qui n’a pas d’associé', '‘Afḍalou mā qoultou ‘anā wa n-nabiyyoūna min qablī lā ‘ilāha illa l-Lāhou waḥdahou lā charīka lah', NULL, 'Foi, Croyance, Prophètes, Paroles');
INSERT INTO hadiths (id, sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (46, 'Comportement', 'Mouslim', NULL, 'Sahih', ' مَن رَّأَى مِنْكُم مُّنكَراً فَلْيُغَيِّرْهُ بِيَدِهِ فإن لم يستطع فبلسانه فإن لم يستطع فبقلبه وذلك أضعف الإيمان', 'Celui d’entre vous qui a su qu’un mal se pratique, qu’il le change par sa main, s’il est incapable, avec sa langue et s’il est incapable, qu’il déteste cela par son cœur, et ceci étant le minimum que la foi exige', 'man-ra’â minkoum mounkaran falyoughayyirhou biyadih fa’in lam yastaṭi` fabilisânihi fa’in lam yastaṭi` fabiqalbihi wa dhâlika ’aḍ`afou l-’îmân', 'Ce qui est visé par (ra’ā) dans le ḥadīth c’est le fait de prendre connaissance de cette chose blâmable et non pas particulièrement de la voir de ses yeux. Ainsi cette ’âyah et ce ḥadīth indiquent clairement qu’il est permis en Islam de juger les gens selon les règles la loi de Dieu pour ainsi les corriger ou réprouver cela par le cœur. Par contre, si quelqu’un est capable de réprouver par la main ou la parole, il ne lui est pas suffisant de le réprouver par le cœur, et cette réprobation ne le sauve pas de la désobéissance à Allāh. Celui qui est sauvé de la désobéissance, c’est celui qui l’a réprouvé par la main s’il en est capable, s’il ne peut pas par la langue et s’il ne peut pas par le cœur.', 'Foi, Comportement');
INSERT INTO hadiths (id, sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (47, 'Pêchés', ' At-Tirmîdhiyy', NULL, 'Sahih', 'لَا طَاعَةَ لِمَخْلُوقٍ فِي مَعْصِيَةِ الْخَالِقِ ', 'on n’obéit pas à une créature pour désobéir au Créateur ', NULL, 'Il convient au musulman de faire preuve de bon comportement, de patience et d’indulgence envers les musulmans et non musulmans, mais il ne doit pas les aider à ce qui est interdit par l’Islam ni approuver leurs péchés, On doit obéir en priorité à Dieu le créateur du monde, Qui nous a accordé le fait d’exister, de respirer, de voir, d’entendre et des bienfaits que nous ne pouvons dénombrer. Ainsi il n’est pas permis d’aider à commettre les péchés ni à la mécréance, en effet aider au péché est un péché et aider à la mécréance est de la mécréance, de même approuver la mécréance est de la mécréance. Donc il est interdit d’offrir des boissons alcoolisées par exemple ou de la viande qui n’est pas égorgée ou du porc à un musulman ou un non musulman. De même il est interdit d’inciter une personne à prononcer la mécréance, en lui posant des questions pour l’amener à dire de la mécréance. Aussi il est interdit d’aider la personne à pratiquer la mécréance tels que les rituels des non musulmans. De même il n’est pas permis de faire croire à quelqu’un qui fait un péché ou une mécréance que ceci est correcte ou bien. Tout comme il n’est pas permis de faire croire à un non musulman (y compris l’apostat) qu’il est sur la vérité ou qu’il aurait des récompenses dans l’au delà. Par exemple si un musulman a insulté Dieu et qu’il n’est pas revenu à l’Islam en délaissant la mécréance et en prononçant les deux témoignages, il n’est pas permis de lui faire croire qu’il est toujours musulman. Ainsi dans ce cas il n’est pas permis de lui demander de faire la prière ou le jeûne tant qu’il n’est pas revenu à l’Islam.', 'Pêchés, Obeissance');
INSERT INTO hadiths (id, sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (48, 'Pêchés', 'Al-Boukhâriyy', NULL, 'Sahih', 'مَثَلُ القائمِ في حدود الله (الّذي يسعى في دفعِ المنكراتِ وإزالتها) والواقعِ فيها كمثل قومٍ اسْتهَمُوا على سَفينَةٍ فصارَ بعضُهم أعلاها وبعضُهم أسفلها وكان الذين في أسفلِها إذا اسْتَقَوْا من الماءِ مرُّوا على من فوقَهم فقالوا : لو أنّا خَرَقْنا في نَصيبِنا خَرْقاً ولم نُؤذ من فَوقَنا. فإن تَركوهُم وما أَرادوا هَلَكوا جميعاً وإن أَخَذوا على أَيديهِم نَجَوْا ونَجَوْا جميعاً', ' L’exemple de celui qui ordonne le bien et interdit le mal et celui qui ne le fait pas est à l’image de voyageurs qui avaient procédé à un tirage et suite à cela ils se sont répartis entre le pont et la cale d’un navire. Les passagers qui étaient sur le pont pouvaient facilement se procurer l’eau du fleuve. Mais ceux qui se trouvaient dans la cale devaient monter pour remplir leur récipient, puiser l’eau, et redescendre avec leurs seaux. Certains de ceux qui étaient dans la cale du navire se sont dit et si nous creusions un trou dans une planche pour puiser l’eau directement, sans avoir à déranger ceux qui étaient sur le pont. Ainsi si les autres les laissaient faire cela, tous vont périr, et s’ils les en empêchaient, tous allaient être sauvés.', NULL, 'Nous tirons de ce ḥadīth une moralité très importante: si la personne délaisse l’interdiction de ce qui est blâmable tout en étant capable, elle tombe elle même dans le péché et laisse autrui dans le péché et l’erreur.', 'Pêchés, Obeissance');
INSERT INTO hadiths (id, sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (49, 'Croyance', 'At- Tirmidhiyy', NULL, 'Haçan', 'إِنَّ العَبْدَ لَيَتَكَلَّمُ بِالكَلِمَةِ لا يَرىَ بِهَا بَأْساً يَهْوِي بِهَا فِي النَّارِ سَبْعِينَ خَرِيفاً ', 'Certes, il arrive que quelqu’un dise une parole dans laquelle il ne voit pas de mal, mais à cause de laquelle il chutera en enfer pendant soixante-dix automnes', '‘inna l-^abda layatakallamou bi l-kalimati la yara biha ba’san yahwi biha fi n-nari sab^ina kharifa', 'C''est-à-dire une distance parcourue en soixante-dix ans de chute pour atteindre le fond de l’enfer, le fond de l’enfer étant réservé aux mécréants.', 'mécréance, apostasie, enfer');
INSERT INTO hadiths (id, sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (50, 'Meilleur parole', 'Imam Malik dans Al-Mouwata', NULL, 'Sahih', 'أَفْضَلُ مَا قُلْتُ أَنَا وَالنَّبِيُّونَ مِنْ قَبْلِي لا إِلهَ إِلَّا اللَّهُْ', 'La meilleure des paroles que j’ai dite, moi ainsi que les prophètes avant moi c’est لا إِلَهَ إِلَّا اللَّهُ “Il n’est de Dieu que Dieu.', NULL, NULL, 'Révélation, croyance, parole');
INSERT INTO hadiths (id, sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (51, 'Meilleur des oeuvres', 'Al-Boukhariyy', NULL, 'Sahih', ' إِيمَانٌ بِاللَّهِ وَرَسُولِهُِْ', 'La foi en Dieu et en Son messager.', NULL, 'A propos de la croyance en Dieu et en son messager citons le حديث hadith suivant  [rapporté par Al-Boukhariyy]:  Le Messager de Dieu صلَّى الله عليه وسلم fut interrogé : « Quelle est la meilleure des œuvres ? », Donc la plus honorable et la meilleure des œuvres dans l’absolu, c’est d’avoir la foi correcte en Dieu et en Son messager. Et il se peut que quelqu’un te pose la question : « Mais il y a des حديث hadith dont le sens apparent est que la meilleure des œuvres, c’est la prière dans son temps. » En fait, on a su que la foi précède la prière dans le degré à partir d’autres حديث hadith parce que le Prophète صلَّى الله عليه وسلم, sa Loi toute entière est comme un seul énoncé, comme un tout qui se complète, c’est-à-dire qu’on a su que la foi est au-devant à partir de l’ensemble de ce qu’a amené le Prophète عليه الصلاة والسلام.', 'Oeuvres, croyance, parole');
INSERT INTO hadiths (id, sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (52, 'Mawlid', 'Ahmad et par Al-Bayhaqiyy dans Ad-Dala’il', NULL, 'Sahih', 'ذاكَ يَوْمٌ وُلِدْتُ فِيهِ وأُنْزِلَ عَلَيَّ فِيهُِِْ', 'C’est un jour dans lequel je suis né et dans lequel la révélation a commencé à descendre sur moi.', 'dhaka yawmoun woulidtou fihi wa‘ounzila ^alayya fih', 'C''est la réponse de notre bien aimé prophète lorsqu''il a été interrogé sur son jeûne les lundis', 'Mawlid');
INSERT INTO hadiths (id, sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (53, 'Bonne croyance', 'At–Tabaraniyy', NULL, 'Sahih', ' الْمُتَمَسِّكُ بِسُنَّتِي – أَيْ شَرِيعَتِي مِنَ العَقِيدَةِ والأَحْكامِ – عِنْدَ فَسادِ أُمَّتِي لَهُ أَجْرُ شَهِيدٍُِِْ', 'Celui qui s’attachera à ma voie – c’est-à-dire à ma chari^ah, à ce qu’elle comporte comme croyances et comme jugements pratiques – lorsque le mal se propagera au sein de ma communauté, aura la récompense d’un martyr.', 'al-moutamassikou bi-sounnati ^inda façadi ‘oummati lahou ‘ajrou chahid', NULL, 'Bonne croyance');
INSERT INTO hadiths (id, sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (54, 'croyance, ta’wil, Qour’an', 'At–Tabaraniyy', NULL, 'Sahih', 'الْقُرْءانُ حُجَّةٌ لكَ أَوْ عَلَيكَ', 'Le Qour’an est soit une preuve en ta faveur, soit une preuve contre toi', 'Al-Qour’anou houjjatoun laka ‘aw ^alayka', 'Ainsi, celui qui donne une mauvaise interprétation des versets du Qour’an, cela se retournera contre lui.
INSERT INTO coran (id, sujet, sourate, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (1, 'Croyance ', '’Āli `Imrān / ’āyah 190', 'إِنَّ فِي خَلْقِ السَّمَاوَاتِ وَالأَرْضِ وَاخْتِلاَفِ اللَّيْلِ وَالنَّهَارِ لَآيَاتٍ لِأُوْلِي الألْبَابِ ', 'Certes, dans la création des cieux et de la terre et dans le changement du jour et de la nuit, il y a des preuves pour ceux qui sont dotés de raison', 'Inna khalqi fī s-samāwāti wa l-’arḍi wākhtilāfi l-layli wa n-nahāri lāyātin li’oūlī l-’albābi', 'Dans ce verset (‘āyah), Dieu nous indique que le monde est une preuve de Son existence ; ainsi selon la raison, les cieux, la terre et les autres créatures auraient pu ne pas exister ou exister à une autre époque, avec une autre forme, ou avec d’autres caractéristiques. L’existence de ces créatures signifie qu’il y a Un Créateur Qui les a spécifiées par le fait d’exister au lieu de ne pas exister, d’exister à cette époque plutôt qu’à une autre, d’avoir ces caractéristiques plutôt que d’autres.', 'croyance');
INSERT INTO coran (id, sujet, sourate, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (2, 'Croyance ', 'Al-’A`rāf / ‘āyah 185', 'أَوَلَمْ يَنظُرُوا في مَلَكُوتِ السَّمـٰواتِ والأرضِ', 'Ne méditent-ils pas au sujet des cieux et de la terre ?', '’awalam yanḍhouroū fī malakoūti s-samāwāti wa l-’arḍ', 'Ce verset (‘āyah) blāme le fait de ne pas méditer sur la création', 'croyance');
INSERT INTO coran (id, sujet, sourate, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (3, 'Croyance ', 'soūrat al-Moulk / ’āyah 10', 'وَقَالُوا لَوْ كُنَّا نَسْمَعُ أَوْ نَعْقِلُ مَا كُنَّا فِي أَصْحَابِ السَّعِيرِ', 'et ils ont dit si nous avions écouté [avec acceptation] ou si nous avions raisonné, nous n’aurions pas fait partie des gens de l’enfer', NULL, 'Ces versets nous indiquent que la raison est une preuve dans la religion. Bien que la base de la religion soit le Qour’ān et le ḥadīth, la raison est un témoin de la religion. Ainsi, rien de ce qui est parvenu dans la religion, ne contredit la raison.', 'croyance');
INSERT INTO coran (id, sujet, sourate, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (4, 'Croyance ', NULL, 'وَهُوَ مَعَكُمۡ أَيۡنَ مَا كُنتُمۡۚ', 'Cela veut dire qu’Il sait toute chose par Sa science.', 'Wahouwa ma^akoum ‘ayna ma kountoum', 'C’est ce qu’ont dit Ath-Thawriyy, Ach-Chafi^iyy, Ahmad, Malik et bien d’autres', 'croyance');
INSERT INTO coran (id, sujet, sourate, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (5, 'Croyance, ta’wil', 'Al-Baqarah / 26', 'يُضِلُّ بِهِ كَثِيرًا وَيَهْدِي بِهِ كَثِيرًاۡۚ', 'Allah égare par le Qour’an beaucoup de gens et Il guide par lui beaucoup de gens.', 'Youdillou bihi kathiran wayahdi bihi kathira', 'Ainsi, Allah a voulu de toute éternité que certains soient guidés par le Qour’an et que d’autres soient égarés par leur mauvaise interprétation des versets non explicites du Qour’an.
INSERT INTO dhikrs (id, sujet, texte_arabe, texte_francais, phonetique, explication, commentaire, tag) VALUES (1, 'Dhikr', 'لا إله إلا الله محمد رسول الله', 'Il n’y a de dieu qu’Allah et Muhammad est son messager.', 'Lā ilāha illā Allāhou Muhammadou rasoulou Allāh', '', 'La base de la croyance islamique.', 'croyance, tawhid');
INSERT INTO dhikrs (id, sujet, texte_arabe, texte_francais, phonetique, explication, commentaire, tag) VALUES (2, 'Invocation quand on se réveille au milieu de la nuit', 'أَعُوذُ بكلماتِ اللهِ التآماتِ من غضبِهِ وعقابِهِ وشَرِّ عبادِهِ ومِنْ هَمَزَاتِ الشَّيَاطِينِ وأَنْ يَحضُرُونَ', 'Nous enseignons cette dhikr à ceux qui avait atteint le discernement parmi nos enfants. Et ceux qui n’avait pas encore atteint le discernement, on l’écrivait et on l’accrochait à leurs cous', '''a`ôudhou bi kalimâti l-Lâhi t-tâmmâti min ghaḍabihi wa `iqâbih wa charri `ibâdih wa min hamazâti ch-chayâṭîn wa ''an yaḥḍourôun', 'Invocation demandant la paix et la protection.', 'At-tirmîdhiyy a dit: « c’est un ḥadīth qui est ḥaçan »', 'protection');
INSERT INTO dhikrs (id, sujet, texte_arabe, texte_francais, phonetique, explication, commentaire, tag) VALUES (3, 'Dhikr', 'الله الله ربّي لا أُشركُ به شيئًا', 'Allāh, Allāh est mon Seigneur, je ne lui associe rien.', 'Allāhou Allāhou rabbī lā `ouchrikou bihī chay`â', '', 'Évocation à faire matin et soir.', 'tahsin, protection');
INSERT INTO douaas (id, sujet, texte_arabe, texte_francais, phonetique, explication, commentaire, tag) VALUES (1, 'Invocation à dire lorsque le vent souffle ', 'اللَّهُمَّ إِنِّي أسْألُكَ خَيْرَهَا وخَيْرَ مَا فِيْهَا وَخَيْرَ مَا أُرْسِلَتْ بِهِ وأعُوذُ بِكَ مِنْ شَرِّهَا وَشَرِّ مَا فِيْهَا وَشَرِّ مَا أُرْسِلَتْ بِهِِ', 'Ô mon Dieu, je Te demande son bien, le bien qu’il contient et le bien avec lequel il a été envoyé, et je cherche refuge auprès de Toi contre son mal, le mal qu’il contient et le mal avec lequel il a été envoyé.', '', '', '', 'vent');
INSERT INTO savants (id, sujet, savant, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (1, 'La non ressemblance de Allah', 'Abu Hanifah', 'يد الله فوق أيديهم، وليست كأيدي خلقه، ليست بجارحة، وهُو خالق الأيدي. ووجهُه ليس كوُجوه خلقه، وهُو خالق كُلِّ الوُجوه', ' اليد (al-yad) attribué à Dieu n’a aucune ressemblance avec les mains des créatures. Ce n’est pas un membre. Il est le Créateur des mains. الوجه (al-wajh) attribué à Dieu n’a aucune ressemblance avec les visages des créatures. Il est le Créateur de tous les visages.', NULL, 'Un autre argument qui montre que Abou Hanifah ne rejette pas toute interprétation, réside dans sa parole dans Al-Fiqh al-Absaṭ où il dit lorsqu’il parle de l’attribut de Dieu اليد (al-yad)', 'Exemption, croyance, Attributs de Dieu');
INSERT INTO savants (id, sujet, savant, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (2, 'La non ressemblance de Allah', 'Abu Hanifah', 'فمَا ذكره الله تعالَى في القُرآن مِن ذكر الوجه واليد والنَّفس، فهُو له صفة بلا كيف', 'ce que Dieu a cité dans le Qour’an à savoir الوجه, اليد et النَّفس, il s’agit d’attributs de Dieu sans comment', NULL, 'Sa parole “sans comment” est une interprétation qui rejette le sens littéral, il s’agit d’une interprétation globale car il n’a pas précisé le sens voulu.', 'Exemption, croyance, Attributs de Dieu');
INSERT INTO savants (id, sujet, savant, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (3, 'La non ressemblance de Allah', 'Abu Hanifah', 'ويراه المُؤمنون وهُم في الجنَّة بأعيُن رُؤوسهم بلا تشبيه ولا كيفيَّة ولا كمِّيَّة ولا يكون بينه وبين خلقه مسافة', ' Les croyants Le verront de leurs yeux, sans aucune ressemblance avec les créatures, ni comment, ni quantité, et sans qu’il y ait une distance entre Lui et eux.', NULL, 'Et dans Al-Fiqh al-Akbar il ajoute à propos de la vision de Dieu au Paradis', 'Exemption, croyance, Attributs de Dieu');
INSERT INTO savants (id, sujet, savant, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (4, 'La non ressemblance de Allah', 'Al-Matouridiyy', 'بَلْ يَدَاهُ مَبْسُوطَتَانِ', 'Par ailleurs, Al-Matouridiyy — qui était hanafite — a commenté le verset 64 de sourate Al-Mai’dah : En disant qu’il signifie : « Ses bienfaits sont largement répandus » c’est-à-dire que Dieu accorde ses bienfaits à qui Il veut et Il prive qui Il veut.', NULL, 'Et il a ajouté : « Concernant les termes cités comme اليد, القبضة ou اليمين, il s’agit de Lui attribuer la force, la souveraineté et la puissance sur toute chose. » Cette interprétation montre que Al-Matouridiyy a bien compris que Abou Hanifah ne voulait pas exclure systématiquement toute interprétation du terme اليد par le bienfait car il l’a interprété lui-même par ce sens dans le verset de sourate Al-Mai’dah.', 'Exemption, croyance, Attributs de Dieu');
INSERT INTO savants (id, sujet, savant, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (5, 'La non ressemblance de Allah', 'Imam At–Tahawiyy ', 'وَمَنْ وَصَفَ اللهَ بِمَعْنًى مِنْ مَعَانِي البَشَرِ فَقَدْ كَفَر', 'Celui qui qualifie Dieu par une des attributs des humains aura mécru » c’est-à-dire qu’il n’est pas musulman.', NULL, NULL, 'Exemption, croyance, Attributs de Dieu');
INSERT INTO savants (id, sujet, savant, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (6, 'La non ressemblance de Allah', 'Imam Ach-Chafi^iyy ', 'مَنِ انْتَهَضَ لِمَعرِفةِ مُدَبِّرِهِ فَانتَهَى إِلى مَوجُودٍ يَتَصَوَّرُهُ بِفِكرِهِ فَهُوَ مُشَبِّه ومَنِ انتَهَى إِلى العَدَمِ الصِّرْفِ فهُوَ مُعَطِّل ومَنِ انتَهَى إِلى مَوجُودٍ واعْتَرَفَ بِالعَجْزِ عَنْ إِدْراكِهِ فَهُوَ مُوَحِّد', 'Celui qui tente de connaître son Créateur et qui aboutit à un être qu’il imagine par son esprit, c’est un assimilationniste et Celui qui aboutit à l’inexistence du Créateur c’est un athée. Et celui qui aboutit à l’existence d’un Créateur en reconnaissant qu’il est incapable d’en connaître la réalité, c’est un croyant en l’Unicité de Dieu.', NULL, 'Reprenons phrase par phrase la parole de l’Imam Ach-Chafi^iyy
INSERT INTO savants (id, sujet, savant, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (7, 'L''interpretation Qour’an', 'Ahmad Ar-Rifa^iyy', 'صونو عقائدكم من التّمسّك بظاهر ما تشابه من الكتاب والسّنّة فإنّ ذالك من أصول الكفر
INSERT INTO savants (id, sujet, savant, texte_arabe, texte_francais, phonetique, explication, tag) VALUES (8, 'La non ressemblance de Allah', 'Imâm Abou l-Mou’în Maymoûn An-Naçafi', ' ويجوز أن يقال بأن لله تعالى يداً بالعربية ، ولا يجوز بالفارسية ، واليد من صفاته الأزلية بلا كيف ولا تشبيه كالسمع والبصر والعلم والقدرة والحياة والإرادة والكلام. فإن الله تعالى سميع بلا جارحة ، بصير بلا عين ، عالم بلا آلة ، مريد بلا قلب ، متكلم بلا لسان وشفتين ، وكذلك اليد من صفاته الأزلية بلا كيف وتشبيه وجارحة. فنقرُّ باليد والمراد به ما أراد الله تعالى', 'l est permis de dire que Allâh ta’âlâ a un yad en Arabe, mais ce n’est pas permis en Persan. Et al-yad est l’un de Ses attributs éternels, sans comment (bila kayf) et sans similarité (wa lâ tachbîh) comme l’ouïe, la vue, la science, la puissance, la vie, la volonté, et la parole. Ainsi, Allâh ta’âlâ entend sans organe, Il voit sans œil, Il sait [toutes choses] sans appareils, Il a la volonté sans qu’Il n’ait de cœur, Il parle sans langue ni lèvres. Il en est de même pour al-yad qui compte de parmi Ses attributs éternels sans comment, ni similarité, et qui n’est pas un membre. Ainsi, nous confirmons al-yad, et son sens est tel que Allâh ta’âlâ veut', NULL, 'L’Imâm, Al-Moutakallim (le spécialiste de la croyance), Al-Ousoûli (le spécialiste des fondements) Abou l-Mou’în Maymoûn Ibnou Mouhammad An-Naçafi Al-Hanafi Al-Mâtourîdi est né en 418 et il est décédé en 508 de l’Hégire (رحمه الله) c’est-à-dire il y a environ 930 ans.
